refsection.programlisting:

[func,names] = auto_test('test=arlm(6),jbnorm,chowtest(0.8),myautocor(5)')
// creates a function that performs the Breusch and Pagan test with 1 to 6 lags,
// the Jarque and Bera normality test, the Chow stability test with a break at 80%
// of the sample and the matrix of corresponding names.

[test_func,m2prt_test]=auto_test(grocer_ltest)
// This example is an application of auto_test in function automatic.
